import androidx.appcompat.app.AppCompatActivity

class DeepLinkActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val uri = intent?.data
        DeepLinkRouter.route(this, uri)

        finish()
        overridePendingTransition(0, 0)
    }
}

object DeepLinkRouter {
    private const val SCHEME = "myapp"

    fun route(context: Context, uri: Uri?) {
        val intent = createIntent(context, uri)
        context.startActivity(intent)
        if (context is Activity) {
            context.overridePendingTransition(0, 0)
        }
    }

    fun createIntent(context: Context, uri: Uri?): Intent {
        if (uri == null) return defaultIntent(context)

        if (!uri.scheme.equals(SCHEME, ignoreCase = true)) {
            return defaultIntent(context)
        }

        val host = (uri.host ?: "").lowercase()
        val segments = uri.pathSegments ?: emptyList()

        return when {
            host == "profile" -> {
                val id = segments.firstOrNull()?.toLongOrNull()
                if (id != null) {
                    ProfileActivity.createIntent(context, id)
                } else {
                    defaultIntent(context)
                }
            }

            host == "payment" && segments.firstOrNull()?.equals("confirm", ignoreCase = true) == true -> {
                PaymentConfirmActivity.createIntent(context)
            }

            else -> defaultIntent(context)
        }.apply {
            addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP or Intent.FLAG_ACTIVITY_SINGLE_TOP)
        }
    }

    private fun defaultIntent(context: Context): Intent {
        return MainActivity.createIntent(context).apply {
            addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP or Intent.FLAG_ACTIVITY_SINGLE_TOP)
        }
    }
}

class MainActivity : AppCompatActivity() {
    companion object {
        fun createIntent(context: Context): Intent =
            Intent(context, MainActivity::class.java).apply {
                if (context !is Activity) addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
            }
    }
}

